  builder.AddBooleanProperty("PS", [this] { return GetPSButton(); }, nullptr);
  builder.AddBooleanProperty("Options", [this] { return GetOptionsButton(); }, nullptr);
  builder.AddBooleanProperty("L3", [this] { return GetL3Button(); }, nullptr);
